# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
import getpass

db_host = input("Enter database host: ")
db_user = input("Enter database user: ")
db_password = getpass.getpass("Enter database password: ")
db_name = input("Enter database name: ")
table_name = input("Enter target table name: ")
file_path = input("Enter the full path to the data file: ")
# Example: '/path/to/your/data.csv' or 'C:\\path\\to\\your\\data.csv'

# You might want to allow the user to specify these or hardcode for your ETL
fields_terminated_by = input("Enter field terminator (e.g., ',' for CSV, '\\t' for TSV): ")
lines_terminated_by = input("Enter line terminator (e.g., '\\n'): ")
# Example: ',' for CSV files, '\t' for TSV files
# Example: '\n' for Unix/Linux, '\r\n' for Windows

# Optional: Header row handling
ignore_lines = input("Number of lines to ignore at the beginning (e.g., 1 for header row, 0 for none): ")
try:
    ignore_lines = int(ignore_lines)
except ValueError:
    print("Invalid number for lines to ignore, defaulting to 0.")
    ignore_lines = 0

try:
    conn = mysql.connector.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        local_infile=True  # Enable LOCAL INFILE for the connection
    )
    cursor = conn.cursor()

    # Construct the LOAD DATA INFILE statement
    load_data_sql = f"""
    LOAD DATA LOCAL INFILE '{file_path}'
    INTO TABLE {table_name}
    FIELDS TERMINATED BY '{fields_terminated_by}'
    LINES TERMINATED BY '{lines_terminated_by}'
    IGNORE {ignore_lines} LINES;
    """

    print(f"\nExecuting SQL:\n{load_data_sql}")
    cursor.execute(load_data_sql)

    conn.commit()
    print(f"\nSuccessfully imported data from '{file_path}' into table '{table_name}'.")
    print(f"{cursor.rowcount} rows imported.")

except mysql.connector.Error as err:
    print(f"Error: {err}")
    print("\nPlease ensure:")
    print("1. 'local_infile = 1' is enabled in your MySQL server configuration (my.cnf or my.ini).")
    print("2. The MySQL user has FILE privilege (GRANT FILE ON *.* TO 'your_user'@'your_host';).")
    print("3. The Python script has read access to the specified file path.")
    print("4. The file path, table name, and terminators are correct.")

finally:
    if 'conn' in locals() and conn.is_connected():
        cursor.close()
        conn.close()
        print("Database connection closed.")